def load_shops_master(shop_list_path):
    if shop_list_path is None:
        return DEFAULT_SHOPS_MASTER
    shops = pd.read_excel(shop_list_path)
    records = [
        {
            "code": str(r["SHOP CODE"]),
            "name": r["SHOP NAME"],
            "type": r["TYPE SHOP"],
            "region": r["REGION"],
            "area": r["AREA"],
            "size": r["Size Shop"],
        }
        for _, r in shops.iterrows()
    ]
    return json.dumps(records, ensure_ascii=False)

def export_group(df, prodgroup):
    f = df[(df["TYPE SHOP"].isin(["Hall", "COCO"])) & (df["CUSTOM_PRODGROUP"] == prodgroup)].copy()
    f = f[["DATE", "REGION", "AREA", "SHOP_CODE", "SHOP NAME", "TYPE SHOP", "QTY", "NET_AMOUNT", "CUSTOM_BRAND", "CUSTOM_MODEL"]]
    f["DATE"] = pd.to_datetime(f["DATE"])
    f = f.sort_values(["DATE", "REGION", "AREA", "SHOP NAME"])
    records = [
        {
            "date": r["DATE"].strftime("%Y-%m-%d"),
            "region": r["REGION"],
            "area": r["AREA"],
            "code": str(r["SHOP_CODE"]),
            "shop": r["SHOP NAME"],
            "type": r["TYPE SHOP"],
            "qty": int(r["QTY"]),
            "rev": int(r["NET_AMOUNT"]),
            "brand": r["CUSTOM_BRAND"],
            "model": r["CUSTOM_MODEL"],
        }
        for _, r in f.iterrows()
    ]
    return records, f

def build(xlsx_path: str, out_path: str, shop_list_path: str = None):
    df = pd.read_excel(xlsx_path, sheet_name="TSM")

    handset_records, handset_f = export_group(df, "HANDSET")
    accessories_records, accessories_f = export_group(df, "ACCESSORIES")

    handset_json = json.dumps(handset_records, ensure_ascii=False)
    accessories_json = json.dumps(accessories_records, ensure_ascii=False)
    shops_json = load_shops_master(shop_list_path)

    html = (
        TEMPLATE
        .replace("__CSS__", CSS)
        .replace("__BODY__", BODY)
        .replace("__HANDSET_DATA__", handset_json)
        .replace("__ACCESSORIES_DATA__", accessories_json)
        .replace("__SHOPS__", shops_json)
        .replace("__JS__", JS)
    )
    with open(out_path, "w", encoding="utf-8") as fh:
        fh.write(html)

    n_shops_master = len(json.loads(shops_json))
    print(f"OK -> {out_path}")
    print(f"    Handset:     {len(handset_records)} rows | {handset_f['QTY'].sum():,} units | {handset_f['NET_AMOUNT'].sum():,} THB")
    print(f"    Accessories: {len(accessories_records)} rows | {accessories_f['QTY'].sum():,} units | {accessories_f['NET_AMOUNT'].sum():,} THB")
    print(f"    Shop master list: {n_shops_master} shops ({'from file' if shop_list_path else 'baked-in default'})")

if __name__ == "__main__":
    xlsx_path = sys.argv[1] if len(sys.argv) > 1 else "Refresh_TSM.xlsx"
    out_path = sys.argv[2] if len(sys.argv) > 2 else "Handset_Sales_Dashboard.html"
    shop_list_path = sys.argv[3] if len(sys.argv) > 3 else None
    build(xlsx_path, out_path, shop_list_path)
